'use client';

import { useState } from 'react';
import Link from 'next/link';
import { Plus, Search, Globe, Award, Edit2 } from "lucide-react";
import { BrandFormModal } from './BrandFormModal';

type BrandManagerProps = {
    brands: any[]; // using any for speed, ideally typed
    countries: any[];
    categories: any[]; // NEW: Categories for linking
};

export function BrandManager({ brands, countries, categories }: BrandManagerProps) {
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editingBrand, setEditingBrand] = useState<any>(null);
    const [searchTerm, setSearchTerm] = useState('');

    const filteredBrands = brands.filter(b =>
        b.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
        b.country?.name.toLowerCase().includes(searchTerm.toLowerCase())
    );

    const handleEdit = (brand: any) => {
        setEditingBrand(brand);
        setIsModalOpen(true);
    };

    const handleCreate = () => {
        setEditingBrand(null);
        setIsModalOpen(true);
    };

    return (
        <div className="space-y-6">
            {/* Header Controls */}
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
                <div>
                    <h1 className="text-4xl font-bold text-gray-900 tracking-tight mb-2">Brands</h1>
                    <p className="text-gray-500">Manage manufacturers and product brands.</p>
                </div>
                <div className="flex gap-3">
                    <Link
                        href="/admin/inventory/maintenance?tab=brand"
                        className="bg-white border border-gray-200 text-gray-700 hover:bg-gray-50 hover:text-emerald-600 px-4 py-3 rounded-xl font-semibold shadow-sm transition-all flex items-center gap-2"
                    >
                        <Edit2 size={20} /> {/* Reusing Edit2 or change to Wrench if imported */}
                        <span>Reorganize</span>
                    </Link>
                    <button
                        onClick={handleCreate}
                        className="bg-emerald-600 text-white px-6 py-3 rounded-xl font-semibold shadow-lg hover:shadow-emerald-900/20 hover:-translate-y-0.5 transition-all flex items-center gap-2"
                    >
                        <Plus size={20} />
                        <span>Add New Brand</span>
                    </button>
                </div>
            </div>

            <div className="card-premium p-6">
                {/* Filter Header */}
                <div className="flex justify-between items-center mb-6 pb-4 border-b border-gray-100">
                    <div className="relative">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
                        <input
                            type="text"
                            placeholder="Search brands..."
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                            className="pl-10 pr-4 py-2 border border-gray-200 rounded-lg text-sm focus:outline-none focus:border-emerald-500 w-64 transition-all"
                        />
                    </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                    {filteredBrands.length === 0 ? (
                        <div className="col-span-full py-12 text-center text-gray-400">
                            <p>No brands found.</p>
                        </div>
                    ) : (
                        filteredBrands.map((brand) => (
                            <div key={brand.id} className="group border border-gray-100 rounded-2xl p-6 hover:shadow-lg transition-all bg-white relative overflow-hidden">
                                <div className="absolute top-0 right-0 p-4 opacity-5 group-hover:opacity-10 transition-opacity">
                                    <Award size={64} />
                                </div>
                                <button
                                    onClick={() => handleEdit(brand)}
                                    className="absolute top-2 right-2 p-2 bg-gray-50 rounded-full opacity-0 group-hover:opacity-100 transition-opacity hover:bg-emerald-50 text-gray-400 hover:text-emerald-600"
                                >
                                    <Edit2 size={14} />
                                </button>

                                <div className="flex justify-between items-start mb-4">
                                    <div className="w-12 h-12 rounded-xl bg-gray-50 flex items-center justify-center text-xl font-bold text-gray-700 uppercase">
                                        {brand.logo ? (
                                            <img src={brand.logo} alt={brand.name} className="w-full h-full object-cover rounded-xl" />
                                        ) : (
                                            brand.name.substring(0, 2)
                                        )}
                                    </div>
                                    <div className="flex items-center gap-1 text-xs font-semibold bg-blue-50 text-blue-600 px-2 py-1 rounded-lg">
                                        <Award size={12} />
                                        {brand._count?.products || 0} products
                                    </div>
                                </div>

                                <h3 className="text-lg font-bold text-gray-900 mb-1 hover:text-emerald-600 transition-colors">
                                    <Link href={`/admin/inventory/brands/${brand.id}`}>
                                        {brand.name}
                                        {brand.shortName && <span className="ml-2 text-sm text-gray-400 font-normal">({brand.shortName})</span>}
                                    </Link>
                                </h3>

                                {/* Countries */}
                                <div className="flex flex-wrap gap-1 mt-2">
                                    {(brand.countries && brand.countries.length > 0) ? (
                                        brand.countries.map((c: any) => (
                                            <div key={c.id} className="flex items-center gap-1 text-xs bg-gray-50 border border-gray-100 px-1.5 py-0.5 rounded text-gray-600">
                                                <Globe size={10} className="text-gray-400" />
                                                <span>{c.code}</span>
                                            </div>
                                        ))
                                    ) : (
                                        <span className="text-xs text-gray-400 italic">Global / No Specific Country</span>
                                    )}
                                </div>

                                {/* NEW: Categories */}
                                <div className="mt-2 pt-2 border-t border-gray-50">
                                    <p className="text-[10px] font-semibold text-gray-400 uppercase mb-1">Categories:</p>
                                    <div className="flex flex-wrap gap-1">
                                        {(brand.categories && brand.categories.length > 0) ? (
                                            brand.categories.map((cat: any) => (
                                                <span key={cat.id} className="text-xs bg-purple-50 text-purple-700 px-2 py-0.5 rounded font-medium">
                                                    {cat.name}
                                                </span>
                                            ))
                                        ) : (
                                            <span className="text-xs text-gray-400 italic">Universal (All categories)</span>
                                        )}
                                    </div>
                                </div>
                            </div>
                        ))
                    )}
                </div>
            </div>

            {isModalOpen && (
                <BrandFormModal
                    isOpen={isModalOpen}
                    onClose={() => setIsModalOpen(false)}
                    brand={editingBrand}
                    countries={countries}
                    categories={categories}
                />
            )}
        </div>
    );
}
